import{_ as s,c as a,o as e,a as n}from"./app.7f6ac439.js";const u=JSON.parse('{"title":"Identificadores","description":"","frontmatter":{},"headers":[{"level":2,"title":"Errores accesibles","slug":"errores-accesibles"},{"level":2,"title":"Estado de entrada expl\xEDcito","slug":"estado-de-entrada-explicito"},{"level":2,"title":"No deshabilites el bot\xF3n de enviar","slug":"no-deshabilites-el-boton-de-enviar"},{"level":2,"title":"Terminando","slug":"terminando"}],"relativePath":"guide/identifiers.md"}'),o={name:"guide/identifiers.md"},l=n(`<h1 id="identificadores" tabindex="-1">Identificadores <a class="header-anchor" href="#identificadores" aria-hidden="true">#</a></h1><div class="info custom-block"><p class="custom-block-title">INFO</p><p><a href="https://github.com/CaribesTIC/vue-forms-app/tree/l10-start" target="_blank" rel="noopener noreferrer">C\xF3digo previo a la lecci\xF3n</a></p></div><p>En la lecci\xF3n anterior digimos que hay una manera de relacionar las entradas con las etiquetas usando ientificadores. Esta forma de relacionar elementos <strong>HTML</strong> ser\xE1 \xFAtil m\xE1s adelante cuando veamos los mensajes de <code>error</code>.</p><p>Pasemos directamente a nuestro componente <code>BaseInput</code> y descubramos c\xF3mo crear una relaci\xF3n entre nuestro <code>&lt;label&gt;</code> e <code>&lt;input&gt;</code> usando un <strong>ID</strong>.</p><p>Puede estar pensando que quiz\xE1s la opci\xF3n m\xE1s obvia ser\xEDa agregar una propiedad, para que el padre pueda determinar la identificaci\xF3n del elemento, y luego no tenemos que preocuparnos por eso dentro de nuestro componente. Y tendr\xEDa raz\xF3n... Pero, \xBFy si hubiera una forma en que pudi\xE9ramos generar din\xE1micamente identificadores num\xE9ricos \xFAnicos para cada componente de nuestro formulario sin tener que recurrir a propiedades manuales?</p><p>Vamos a crear un componente Vue 3 que nos permita crear estos identificadores \xFAnicos din\xE1micos, o UUID para abreviar. Es un poco un salto del ritmo del curso, pero vamos a hablar un poco sobre la <a href="https://vuejs.org/api/composition-api-setup.html" target="_blank" rel="noopener noreferrer">Composition API</a> y los <a href="https://vuejs.org/guide/reusability/composables.html" target="_blank" rel="noopener noreferrer">Composables</a>. En cualquier caso, no te preocupes demasiado, va a ser muy sencillo.</p><p>Sigamos adelante y cre\xE9 un archivo UniqueID.js dentro de la carpeta <code>features</code>.</p><p>Vamos a ver.</p><p>\u{1F4C3}<code>UniqueID.js</code></p><div class="language-js"><span class="copy"></span><pre><code><span class="line"><span style="color:#C792EA;">let</span><span style="color:#A6ACCD;"> UUID </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">0</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">export</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">default</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">function</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">UniqueID</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">()</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#C792EA;">const</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">getID</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">=</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">()</span><span style="color:#F07178;"> </span><span style="color:#C792EA;">=&gt;</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#A6ACCD;">UUID</span><span style="color:#89DDFF;">++</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;font-style:italic;">return</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">UUID</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;font-style:italic;">return</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#A6ACCD;">getID</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><p>Primero declaramos una variable <code>let</code> con un valor predeterminado de <code>0</code>. Esto aumentar\xE1 a medida que creamos m\xE1s y m\xE1s componentes: el primer componente tendr\xE1 una identificaci\xF3n de <code>1</code>, el segundo de <code>2</code>, y as\xED sucesivamente.</p><p>Vamos a exportar una funci\xF3n <code>UniqueID</code>. Cuando se ejecuta, esta funci\xF3n devolver\xE1 un objeto que contiene una funci\xF3n bajo la propiedad <code>getID</code>. Esta funci\xF3n aumentar\xE1 en <code>1</code> el contador <code>UUID</code> global y lo devolver\xE1.</p><p>Sepa tambi\xE9n que hay muchas bibliotecas de <code>UUID</code> que puede usar en lugar de esta soluci\xF3n personalizada, pero quer\xEDamos mostrarle lo f\xE1cil que puede ser.</p><p>Veamos esto en acci\xF3n para entenderlo mejor, observando <code>BaseInput.vue</code>.</p><p>Primero, vamos a importar nuestro nuevo composable.</p><p>\u{1F4C3}<code>BaseInput.vue</code></p><div class="language-vue"><span class="copy"></span><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#A6ACCD;"> UniqueID </span><span style="color:#89DDFF;font-style:italic;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">../features/UniqueID</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">export</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">default</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#676E95;font-style:italic;">// omitted for brevity ...</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><p>Ahora que lo tenemos listo, podemos generar una nuevo <strong>ID</strong> \xFAnico dentro del m\xE9todo de <code>setup</code> de nuestro componente. Sigamos adelante y hagamos eso.</p><p>\u{1F4C3}<code>BaseInput.vue</code></p><div class="language-vue"><span class="copy"></span><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#A6ACCD;"> UniqueID </span><span style="color:#89DDFF;font-style:italic;">from</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">../features/UniqueID</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">export</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">default</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">props</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#676E95;font-style:italic;">// omitted for brevity ...</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">setup</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">()</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#C792EA;">const</span><span style="color:#F07178;"> </span><span style="color:#A6ACCD;">uuid</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">=</span><span style="color:#F07178;"> </span><span style="color:#82AAFF;">UniqueID</span><span style="color:#F07178;">()</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getID</span><span style="color:#F07178;">()</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;font-style:italic;">return</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">      </span><span style="color:#A6ACCD;">uuid</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><p>Tenga en cuenta que estamos ejecutando el composable <code>UniqueID</code> y luego el m\xE9todo <code>getID</code> dentro. Esto nos dar\xE1 un n\xFAmero de identificaci\xF3n completamente \xFAnico cada vez que se instancia un componente.</p><p>Finalmente, devolvemos un objeto con el <code>uuid</code> para que podamos usarlo en nuestra plantilla.</p><p>Hablando de eso, volvamos al <code>template</code> y atemos el <code>label</code> y el <code>input</code>.</p><p>Para lograr esto, necesitamos darle al elemento <code>input</code> un valor de atributo <code>id</code>. Vincularemos el <code>id</code> a nuestro <code>uuid</code>. Una vez que tenemos el <code>setup</code> del <code>input</code> con su propio <strong>ID</strong> \xFAnico, ahora podemos decirle al <code>label</code> que describe el <code>input</code> estableciendo el atributo <code>for</code> del <code>label</code>.</p><p>Nota: Todos estos son atributos de vainilla <strong>HTML</strong>, no hay magia loca de Vue aqu\xED aparte de la facilidad de vincularlos a todos.</p><p>\u{1F4C3}<code>BaseInput.vue</code></p><div class="language-vue"><span class="copy"></span><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">label</span><span style="color:#89DDFF;"> :</span><span style="color:#C792EA;">for</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">label</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;{{</span><span style="color:#A6ACCD;"> label </span><span style="color:#89DDFF;">}}&lt;/</span><span style="color:#F07178;">label</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">input</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">v-bind</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">$attrs</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">value</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">modelValue</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">placeholder</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">label</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    @</span><span style="color:#C792EA;">input</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#82AAFF;">$emit</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">update:modelValue</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">, </span><span style="color:#A6ACCD;">$event</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">target</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">value</span><span style="color:#89DDFF;">)</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">field</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  &gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><p>Vuelva al navegador. Lo primero que quiero se\xF1alarles es que la se\xF1al de advertencia en nuestro campo se ha ido. Y si revisamos debajo del <code>bit</code> donde dice <code>relations</code> dentro de las <code>accessible properties</code>, podemos ver ahora que muestra una nueva entrada: etiquetada por: &quot;T\xEDtulo&quot;. Si pasa el cursor sobre este elemento, ahora puede ver en el navegador a qu\xE9 elemento se refiere exactamente. Limpio, \xBFverdad?</p><p>Todav\xEDa necesitamos agregar un <code>uuid</code> a nuestros componentes <code>Checkbox</code>, <code>Radio</code> y <code>Select</code>. \xBFEst\xE1s listo para un desaf\xEDo? Intenta hacer esto t\xFA mismo. Ser\xE1 tan sencillo como replicar exactamente lo que acabamos de hacer aqu\xED con <code>BaseInput</code>.</p><h2 id="errores-accesibles" tabindex="-1">Errores accesibles <a class="header-anchor" href="#errores-accesibles" aria-hidden="true">#</a></h2><p>\xBFAlguna vez llen\xF3 un formulario solo para presionar el bot\xF3n de enviar y nada parec\xEDa funcionar? Claramente no se estaba enviando, y no hab\xEDa ning\xFAn error visible en ninguna parte, sin embargo, algo estaba claramente mal. Esta situaci\xF3n no es ajena a la mayor\xEDa de los usuarios de Internet, pero imagine la exasperaci\xF3n cuando necesita herramientas accesibles y el formulario no le dice f\xE1cilmente cu\xE1l es el problema con sus entradas.</p><p>Primero vayamos a nuestro componente <code>BaseInput.vue</code> y agreguemos una nueva propiedad, <code>error</code>, que nos permitir\xE1 establecer una cadena con un mensaje de error en caso de que el componente se encuentre en un estado de error.</p><p>\u{1F4C3}<code>BaseInput.vue</code></p><div class="language-js"><span class="copy"></span><pre><code><span class="line"><span style="color:#FFCB6B;">props</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#FFCB6B;">label</span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#FFCB6B;">type</span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> </span><span style="color:#FFCB6B;">String</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;font-style:italic;">default</span><span style="color:#F07178;">: </span><span style="color:#89DDFF;">&#39;&#39;</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#FFCB6B;">modelValue</span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#FFCB6B;">type</span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> [</span><span style="color:#FFCB6B;">String</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> </span><span style="color:#FFCB6B;">Number</span><span style="color:#F07178;">]</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;font-style:italic;">default</span><span style="color:#F07178;">: </span><span style="color:#89DDFF;">&#39;&#39;</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#FFCB6B;">error</span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#FFCB6B;">type</span><span style="color:#89DDFF;">:</span><span style="color:#F07178;"> </span><span style="color:#FFCB6B;">String</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">    </span><span style="color:#89DDFF;font-style:italic;">default</span><span style="color:#F07178;">: </span><span style="color:#89DDFF;">&#39;&#39;</span></span>
<span class="line"><span style="color:#F07178;">  </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">},</span></span>
<span class="line"></span></code></pre></div><p>Mostraremos este <code>error</code> debajo de nuestro campo <code>input</code> cada vez que haya un <code>error</code> presente, por lo que si la propiedad de <code>error</code> se establece en algo que no sea una cadena vac\xEDa.</p><p>\u{1F4C3}<code>BaseInput.vue</code></p><div class="language-vue"><span class="copy"></span><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">label</span><span style="color:#89DDFF;"> :</span><span style="color:#C792EA;">for</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">label</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;{{</span><span style="color:#A6ACCD;"> label </span><span style="color:#89DDFF;">}}&lt;/</span><span style="color:#F07178;">label</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">input</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">v-bind</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">$attrs</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">value</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">modelValue</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">placeholder</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">label</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    @</span><span style="color:#C792EA;">input</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#82AAFF;">$emit</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">update:modelValue</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">, </span><span style="color:#A6ACCD;">$event</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">target</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">value</span><span style="color:#89DDFF;">)</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">field</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  &gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">p</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">error</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">errorMessage</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  &gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">{{</span><span style="color:#A6ACCD;"> error </span><span style="color:#89DDFF;">}}</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">p</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><p>Tambi\xE9n volveremos a <code>ComponentsForm.vue</code> y agregaremos un mensaje de <code>error</code> a nuestra entrada &quot;Title&quot;, para que podamos ver c\xF3mo se comporta en el navegador. Tenga en cuenta que tambi\xE9n agregamos una clase de mensaje <code>error</code> que simplemente lo colorear\xE1 de rojo.</p><p>\u{1F4C3}<code>ComponentsForm.vue</code></p><div class="language-html"><span class="copy"></span><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">BaseInput</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">v-model</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">event.title</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">label</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Title</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">type</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">text</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">error</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">This input has an error!</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">/&gt;</span></span>
<span class="line"></span></code></pre></div><p>Ahora echemos un vistazo al navegador, el <code>error</code> se muestra correctamente debajo del t\xEDtulo una vez que se establece la propiedad <code>error</code>. Tenga en cuenta que el <code>input</code> &quot;Description&quot;, que tambi\xE9n es un <code>BaseInput</code>, no muestra ning\xFAn <code>error</code> porque la propiedad <code>error</code> no est\xE1 configurado en nada.</p><p>If we open our Accessibility tab in Firefox once again and inspect the input element, we can see that there is nothing tying the error to the actual title input. This is where most forms fall short. Just because the error message is \u201Cnear\u201D the input doesn\u2019t mean that a screen reader will be able to identify it as part of the error.</p><p>Si abrimos nuestra pesta\xF1a de <strong>Accessibility</strong> en Firefox una vez m\xE1s e inspeccionamos el elemento <code>input</code>, podemos ver que no hay nada que vincule el <code>error</code> con el <code>input</code> del t\xEDtulo real. Aqu\xED es donde la mayor\xEDa de las formas se quedan cortas. El hecho de que el mensaje <code>error</code> est\xE9 &quot;cerca&quot; del <code>input</code> no significa que un lector de pantalla pueda identificarlo como parte del <code>error</code>.</p><p>Afortunadamente, hay una soluci\xF3n sencilla a este problema: el atributo <a href="https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-describedby" target="_blank" rel="noopener noreferrer"><code>aria-describedby</code></a>. Este atributo nos permite declarar directamente en el elemento de entrada qu\xE9 otros elementos lo describen.</p><p>El atributo puede tomar una lista de cadenas de <strong>ID</strong> para otros elementos <strong>HTML</strong> en la p\xE1gina, as\xED que primero agregaremos una <strong>ID</strong> \xFAnica a nuestra etiqueta. Por suerte, ya tenemos un n\xFAmero <strong>UUID</strong> asociado a la instancia del componente para hacerlo.</p><p>Volvamos a <code>BaseInput</code> y agreguemos el v\xEDnculo <code>id</code> a la etiqueta <code>p</code> de <code>error</code>.</p><p>\u{1F4C3}<code>BaseInput.vue</code></p><div class="language-html"><span class="copy"></span><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">p</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">error</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">errorMessage</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">\`\${uuid}-error\`</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  {{ error }}</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">p</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><p>Tenga en cuenta que estamos agregando la cadena <code>-error</code> al <code>UUID</code>. Necesitamos que este identificador sea \xFAnico, y el <code>UUID</code> en s\xED mismo ya est\xE1 en uso por el <code>input</code>.</p><p>Ahora que nuestro mensaje de error tiene un <strong>ID</strong> \xFAnico, podemos establecerlo como una &quot;description&quot; para el elemento <code>input</code> con el atributo <code>aria-describedby</code>.</p><p>\u{1F4C3}<code>BaseInput.vue</code></p><div class="language-vue"><span class="copy"></span><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">label</span><span style="color:#89DDFF;"> :</span><span style="color:#C792EA;">for</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">label</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;{{</span><span style="color:#A6ACCD;"> label </span><span style="color:#89DDFF;">}}&lt;/</span><span style="color:#F07178;">label</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">input</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">v-bind</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">$attrs</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">value</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">modelValue</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">placeholder</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">label</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    @</span><span style="color:#C792EA;">input</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#82AAFF;">$emit</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">update:modelValue</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">, </span><span style="color:#A6ACCD;">$event</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">target</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">value</span><span style="color:#89DDFF;">)</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">field</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">aria-describedby</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">error</span><span style="color:#89DDFF;"> ? </span><span style="color:#89DDFF;">\`\${</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">}</span><span style="color:#C3E88D;">-error</span><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;"> : null</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  &gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">p</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">error</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">errorMessage</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">    :</span><span style="color:#C792EA;">id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;\`\${</span><span style="color:#A6ACCD;">uuid</span><span style="color:#89DDFF;">}</span><span style="color:#C3E88D;">-error</span><span style="color:#89DDFF;">\`&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  &gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">{{</span><span style="color:#A6ACCD;"> error </span><span style="color:#89DDFF;">}}</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">p</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><p>Tenga en cuenta que estamos agregando una verificaci\xF3n secundaria para ver si se establece un <code>error</code>. Esto nos permite un poco de higiene en la relaci\xF3n entre nuestros elementos: cuando no hay ning\xFAn <code>error</code> presente, no se mostrar\xE1 ning\xFAn mensaje de <code>error</code> y la identificaci\xF3n no apuntar\xE1 a nada.</p><p>Si volvemos a revisar nuestro navegador, podemos ver que cuando el <code>error</code> est\xE1 presente, una nueva descripci\xF3n por entrada est\xE1 presente en el objeto de relaci\xF3n de la entrada.</p><p>Sin embargo, una cosa m\xE1s... Debido a que estamos usando <code>v-if</code> para mostrar esta informaci\xF3n de forma intermitente, queremos asegurarnos de que los lectores de pantalla la anuncien o la lean cada vez que se muestre. Para hacer esto, agregaremos un atributo <code>aria-live=&quot;asertive&quot;</code>. Otra forma ser\xEDa agregar un atributo <code>rol</code> de <code>&quot;alert&quot;</code>, pero descubrimos que <a href="https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-live" target="_blank" rel="noopener noreferrer"><code>aria-live</code></a> tiende a funcionar mejor con un variedad de lectores de pantalla.</p><p>\u{1F4C3}<code>BaseInput.vue</code></p><div class="language-html"><span class="copy"></span><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">p</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">v-if</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">error</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">errorMessage</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">\`\${uuid}-error\`</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">aria-live</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">assertive</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  {{ error }}</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">p</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><h2 id="estado-de-entrada-explicito" tabindex="-1">Estado de entrada expl\xEDcito <a class="header-anchor" href="#estado-de-entrada-explicito" aria-hidden="true">#</a></h2><p>Otra cosa que podemos agregar r\xE1pidamente a nuestra entrada para que sea a\xFAn m\xE1s accesible es el atributo <a href="https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-invalid" target="_blank" rel="noopener noreferrer"><code>aria-invalid</code></a>. Un error que se comete en muchos formularios es tratar de confiar en un borde rojo alrededor de una entrada no v\xE1lida. Por razones obvias, esto no es accesible.</p><p>Ya hemos tomado medidas en errores accesibles, pero asegur\xE9monos de notificar tambi\xE9n a los lectores de pantalla sobre el estado no v\xE1lido de una entrada para proporcionar mejores comentarios a nuestros usuarios.</p><p>Vamos a agregar el atributo <code>aria-invalid</code> a nuestra entrada, y lo activaremos y desactivaremos dependiendo de si la propiedad <code>error</code> est\xE1 establecida. Cuando la entrada es v\xE1lida, <code>null</code> har\xE1 que la propiedad no se agregue al elemento de entrada.</p><p>\u{1F4C3}<code>BaseInput.vue</code></p><div class="language-html"><span class="copy"></span><pre><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">input</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">v-bind</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">$attrs</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:value</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">modelValue</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:placeholder</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">label</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">@input</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">$emit(&#39;update:modelValue&#39;, $event.target.value)</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">class</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">field</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:id</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">uuid</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:aria-describedby</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">error ? \`\${uuid}-error\` : null</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#C792EA;">:aria-invalid</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">error ? true : null</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"></span></code></pre></div><p>Si volvemos al navegador e inspeccionamos la entrada usando la herramienta de <strong>Accessibility</strong> en <strong>Firefox</strong>, podemos ver que el estado <code>&quot;invalid&quot;</code> ahora se ha agregado a los estados activos del <code>input</code>.</p><p>Otros estados dignos de menci\xF3n a los que tambi\xE9n podr\xEDamos agregar atributos son de <code>readonly</code>, <code>disabled</code> y <code>required</code>. Estos tres se pueden establecer directamente con atributos <strong>HTML5</strong> del mismo nombre, o con sus contrapartes aria: <a href="https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-readonly" target="_blank" rel="noopener noreferrer"><code>aria-readonly</code></a>, <a href="https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-disabled" target="_blank" rel="noopener noreferrer"><code>aria-disabled</code></a> y <a href="https://developer.mozilla.org/en-US/docs/Web/Accessibility/ARIA/Attributes/aria-required" target="_blank" rel="noopener noreferrer"><code>aria-required</code></a>.</p><h2 id="no-deshabilites-el-boton-de-enviar" tabindex="-1">No deshabilites el bot\xF3n de enviar <a class="header-anchor" href="#no-deshabilites-el-boton-de-enviar" aria-hidden="true">#</a></h2><p>Si un formulario no es v\xE1lido, tiene sentido establecer el atributo <code>disabled</code> en <code>true</code> en el bot\xF3n <code>submit</code> para que el usuario no pueda enviar el formulario, \xBFverdad? Incluso podemos dise\xF1ar el bot\xF3n con un color diferente para transmitir que no se podr\xE1 hacer click en \xE9l.</p><p>Sin embargo, hay un gran problema con esto. Los usuarios que conf\xEDan en los lectores de pantalla no recibir\xE1n ning\xFAn comentario, el lector de pantalla ignorar\xE1 por completo el bot\xF3n al navegar por el formulario. Esto claramente puede ser muy confuso y frustrante.</p><p>En su lugar, sugiero que realice todas y cada una de las comprobaciones para asegurarse de que su formulario sea v\xE1lido antes de enviarlo en el m\xE9todo <code>sendForm</code> que creamos en <code>ComponentsForm</code>. Si todo sale bien, enviamos el formulario normalmente.</p><p>Si algo est\xE1 mal, establesca los errores necesarios en su formulario con las herramientas que acabamos de aprender para notificar al usuario que algo est\xE1 mal.</p><h2 id="terminando" tabindex="-1">Terminando <a class="header-anchor" href="#terminando" aria-hidden="true">#</a></h2><p>Como puede ver, con unas pocas l\xEDneas r\xE1pidas de <strong>HTML</strong> y algunos accesorios colocados estrat\xE9gicamente, logramos convertir nuestro componente <strong>BaseInput</strong> en algo mucho m\xE1s accesible.</p><p>Sin embargo, quiero enfatizar que, en lo que respecta al tema de la accesibilidad, esto solo comienza a ara\xF1ar la superficie. \xA1Pero con estos pocos consejos, deber\xEDamos poder establecer el rumbo para una forma m\xE1s inclusiva y accesible para nuestros proyectos!</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p><a href="https://github.com/CaribesTIC/vue-forms-app/tree/l10-end" target="_blank" rel="noopener noreferrer">C\xF3digo final de la lecci\xF3n</a></p></div>`,74),p=[l];function r(t,c,D,i,F,d){return e(),a("div",null,p)}var m=s(o,[["render",r]]);export{u as __pageData,m as default};
